class Solution:
    def findMinimumTime(self, tasks):
        end_max = max(t[1] for t in tasks)
        best = end_max + 1
        for mask in range(1 << end_max):
            ok = True
            for s, e, d in tasks:
                cnt = 0
                for slot in range(s, e + 1):
                    if mask & (1 << (slot - 1)):
                        cnt += 1
                if cnt < d:
                    ok = False
                    break
            if ok:
                bits = bin(mask).count('1')
                if bits < best:
                    best = bits
        return best

