class Solution:
    def findMinimumTime(self, tasks):
        tasks_sorted = sorted(tasks, key=lambda t: t[1])
        max_time = max(t[1] for t in tasks_sorted)
        on = [False] * (max_time + 1)
        for start, end, duration in tasks_sorted:
            need = duration - sum(1 for t in range(start, end + 1) if on[t])
            t = end
            while need > 0:
                if not on[t]:
                    on[t] = True
                    need -= 1
                t -= 1
        return sum(on)

