var findMinimumTime = function(tasks) {
    const sorted = tasks.slice().sort((a, b) => a[1] - b[1]);
    const maxTime = Math.max(...sorted.map((t) => t[1]));
    const on = new Array(maxTime + 1).fill(false);
    for (const [start, end, duration] of sorted) {
        let need = duration;
        for (let t = start; t <= end; t++) {
            if (on[t]) need--;
        }
        let t = end;
        while (need > 0) {
            if (!on[t]) {
                on[t] = true;
                need--;
            }
            t--;
        }
    }
    return on.filter(Boolean).length;
};
